-- Tamil Nadu Destinations Seed Data
-- Only inserts if destinations table is empty

INSERT INTO destinations (name, category, description, best_season, rating, images, latitude, longitude, created_at)
SELECT * FROM (VALUES
('Ooty', 'Hill Stations', 'Known as the Queen of Hill Stations, Ooty is nestled in the Nilgiri Hills with lush tea gardens, serene lakes, and pleasant weather year-round. The Nilgiri Mountain Railway is a UNESCO World Heritage Site.', 'October to June', 4.7, 'https://images.unsplash.com/photo-1585432959449-57e89990d51d?w=800', 11.4102, 76.6950, NOW()),
('Kodaikanal', 'Hill Stations', 'The Princess of Hill Stations, Kodaikanal is a romantic retreat with misty mountains, pristine waterfalls, and the star-shaped Kodaikanal Lake. Perfect for honeymooners and nature lovers.', 'October to June', 4.6, 'https://images.unsplash.com/photo-1589308078059-be1415eab4c3?w=800', 10.2381, 77.4892, NOW()),
('Yercaud', 'Hill Stations', 'A lesser-known gem in the Shevaroy Hills, Yercaud offers coffee plantations, waterfalls, and the beautiful Emerald Lake. Perfect for a peaceful retreat away from crowds.', 'October to June', 4.3, 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=800', 11.7750, 78.2094, NOW()),
('Valparai', 'Hill Stations', 'A hidden paradise in the Anamalai Hills with 40 hairpin bends leading to vast tea estates, wildlife sanctuaries, and misty viewpoints. Home to rare Nilgiri Tahr.', 'September to May', 4.5, 'https://images.unsplash.com/photo-1470071459604-3b5ec3a7fe05?w=800', 10.3266, 76.9506, NOW()),
('Coonoor', 'Hill Stations', 'Second largest hill station in the Nilgiris, famous for Sims Park, Dolphins Nose viewpoint, and the best tea estates in South India. Less crowded than Ooty.', 'October to March', 4.4, 'https://images.unsplash.com/photo-1518173946687-a9fe4e1b2d00?w=800', 11.3530, 76.7959, NOW()),

('Marina Beach', 'Beaches', 'The second longest urban beach in the world stretching 13 km along Chennai. Iconic landmarks include the lighthouse, ice cream stalls, and the bustling promenade at sunset.', 'November to February', 4.3, 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800', 13.0500, 80.2824, NOW()),
('Rameswaram', 'Beaches', 'A sacred island town connected by the Pamban Bridge. Known for the Ramanathaswamy Temple and its 22 sacred wells. The Dhanushkodi ghost town is hauntingly beautiful.', 'October to April', 4.6, 'https://images.unsplash.com/photo-1559494007-9f5847c49d94?w=800', 9.2876, 79.3129, NOW()),
('Kanyakumari', 'Beaches', 'The southernmost tip of India where three oceans meet. Watch the sunrise and sunset from the same point. The Vivekananda Rock Memorial and Thiruvalluvar Statue are iconic.', 'October to March', 4.5, 'https://images.unsplash.com/photo-1519046904884-53103b34b206?w=800', 8.0883, 77.5385, NOW()),
('Mahabalipuram', 'Beaches', 'UNESCO World Heritage shore temple town with stunning rock-cut monuments, the famous Five Rathas, and Arjunas Penance. Beautiful beach with ancient architecture backdrop.', 'November to February', 4.7, 'https://images.unsplash.com/photo-1476673160081-cf065607f449?w=800', 12.6269, 80.1927, NOW()),
('Covelong Beach', 'Beaches', 'A serene fishing village turned surfing paradise south of Chennai. Perfect for beginners learning to surf with calm waves and golden sand.', 'September to March', 4.2, 'https://images.unsplash.com/photo-1505228395891-9a51e7e86bf6?w=800', 12.7880, 80.2547, NOW()),

('Meenakshi Amman Temple', 'Temples', 'One of the most stunning temples in India located in Madurai. The towering gopurams covered in thousands of colorful sculptures are architectural marvels from the Nayak dynasty.', 'Year-round', 4.9, 'https://images.unsplash.com/photo-1582510003544-4d00b7f74220?w=800', 9.9195, 78.1193, NOW()),
('Brihadeeswarar Temple', 'Temples', 'The Great Living Chola Temple in Thanjavur, a UNESCO World Heritage Site. Built by Raja Raja Chola I in 1010 AD, the massive granite structure showcases Chola architectural genius.', 'Year-round', 4.8, 'https://images.unsplash.com/photo-1621427642691-81e0f2e5c8ab?w=800', 10.7826, 79.1316, NOW()),
('Shore Temple', 'Temples', 'A structural temple built with blocks of granite facing the Bay of Bengal in Mahabalipuram. One of the oldest stone temples in South India, dating back to the 8th century.', 'November to February', 4.7, 'https://images.unsplash.com/photo-1570168007204-dfb528c6958f?w=800', 12.6170, 80.1993, NOW()),
('Ramanathaswamy Temple', 'Temples', 'One of the twelve Jyotirlingas located in Rameswaram. Famous for its 1000-pillar hall and the longest corridor of any Hindu temple in India.', 'Year-round', 4.8, 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?w=800', 9.2881, 79.3174, NOW()),
('Nataraja Temple', 'Temples', 'The famous Chidambaram temple dedicated to Lord Shiva as Nataraja. Features the cosmic dance sculpture and is one of the five Pancha Bhoota Stalas.', 'Year-round', 4.6, 'https://images.unsplash.com/photo-1609947017136-9dae1ee88174?w=800', 11.3992, 79.6932, NOW()),

('Chettinad', 'Heritage', 'A region in Sivaganga district known for its palatial mansions, unique cuisine, and Nattukotai Chettiar heritage. The Athangudi tiles and Chettinad cuisine are world-famous.', 'October to March', 4.5, 'https://images.unsplash.com/photo-1518709268805-4e9042af9f23?w=800', 10.1632, 78.7986, NOW()),
('Tanjore', 'Heritage', 'The cultural capital of Tamil Nadu with rich Chola heritage. Home to the Brihadeeswarar Temple, Tanjore paintings, and classical Carnatic music traditions.', 'October to March', 4.7, 'https://images.unsplash.com/photo-1524492412937-b28074a5d7da?w=800', 10.7870, 79.1378, NOW()),
('Pondicherry', 'Heritage', 'A former French colony with charming colonial architecture, tree-lined boulevards, and vibrant cafes. The French Quarter, Promenade, and Auroville ashram are must-visits.', 'October to March', 4.6, 'https://images.unsplash.com/photo-1580758391737-aad6ba0e8e12?w=800', 11.9416, 79.8083, NOW()),
('Madurai', 'Heritage', 'One of the oldest continuously inhabited cities in the world. The cultural heart of Tamil Nadu with 2500 years of history, the Meenakshi Temple, and vibrant flower markets.', 'October to March', 4.7, 'https://images.unsplash.com/photo-1585320806297-9794b3e4eeae?w=800', 9.9252, 78.1198, NOW()),
('Tranquebar', 'Heritage', 'A tiny Danish colonial settlement on the Coromandel Coast. The Dansborg Fort, colonial churches, and peaceful beaches make it a hidden heritage gem.', 'October to March', 4.3, 'https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=800', 11.0283, 79.8500, NOW()),

('Madurai Street Food Tour', 'Food Trails', 'Experience the legendary street food of Madurai - from Jigarthanda (a cold dessert drink) to Kari Dosa, Mutton Kola Urundai, and the famous Madurai Malli (jasmine). A foodie paradise.', 'Year-round', 4.8, 'https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=800', 9.9252, 78.1198, NOW()),
('Chennai Food Walk', 'Food Trails', 'Explore the diverse food scene of Chennai from traditional Mylapore filter coffee to Marina Beach sundal, Sowcarpet chaat, and the iconic Saravana Bhavan. A culinary journey.', 'Year-round', 4.5, 'https://images.unsplash.com/photo-1567337710282-00832b415979?w=800', 13.0827, 80.2707, NOW()),
('Chettinad Cuisine Trail', 'Food Trails', 'Discover the spiciest and most aromatic cuisine in India. Chettinad pepper chicken, Kavuni arisi, Kuzhi Paniyaram, and authentic wood-fire cooking in ancestral kitchens.', 'October to March', 4.7, 'https://images.unsplash.com/photo-1555939594-58d7cb561ad1?w=800', 10.1632, 78.7986, NOW()),
('Nagercoil Banana Leaf Meals', 'Food Trails', 'The ultimate South Indian banana leaf meals experience in Nagercoil. A 15+ item feast including multiple curries, rasam, sambar, payasam, and crispy appalam.', 'Year-round', 4.4, 'https://images.unsplash.com/photo-1546833999-b9f581a1996d?w=800', 8.1833, 77.4119, NOW()),
('Kumbakonam Filter Coffee Trail', 'Food Trails', 'Follow the aroma of the finest filter coffee in India through Kumbakonam. Visit traditional coffee estates, learn the degree coffee process, and taste perfection.', 'Year-round', 4.6, 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?w=800', 10.9617, 79.3881, NOW()),

('Meghamalai', 'Adventure', 'A cloud forest at 1500m with pristine wilderness, rare wildlife, and tea plantations. Trek through cardamom groves and spot elephants, bison, and exotic birds.', 'September to May', 4.5, 'https://images.unsplash.com/photo-1551632811-561732d1e306?w=800', 9.7264, 77.3478, NOW()),
('Kolli Hills', 'Adventure', 'Home to 70 hairpin bends and 300+ waterfalls. Trek to Agaya Gangai falls, explore ancient caves, and experience the untouched beauty of the Eastern Ghats.', 'October to March', 4.4, 'https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?w=800', 11.2500, 78.3500, NOW()),
('Hogenakkal Falls', 'Adventure', 'The Niagara of India on the Kaveri River. Thrilling coracle rides through the falls, natural jacuzzis, and stunning rock formations make this an adventure paradise.', 'July to January', 4.5, 'https://images.unsplash.com/photo-1432405972618-c6b0cfba0b3f?w=800', 12.1154, 77.7770, NOW()),
('Yelagiri', 'Adventure', 'A lesser-known hill station perfect for paragliding, trekking, and rock climbing. The Punganur Lake and Jalagamparai waterfall are popular spots.', 'October to March', 4.2, 'https://images.unsplash.com/photo-1519681393784-d120267933ba?w=800', 12.5810, 78.6376, NOW()),
('Courtallam', 'Adventure', 'The Spa of South India famous for its medicinal waterfalls. Five major falls with herbs flowing through them are believed to have healing properties.', 'July to September', 4.4, 'https://images.unsplash.com/photo-1433086966358-54859d0ed716?w=800', 8.9317, 77.2712, NOW())
) AS t(name, category, description, best_season, rating, images, latitude, longitude, created_at)
